#!/usr/bin/env bash

set -e

dfx build --ic usdc_ledger
dfx canister stop usdc_ledger --ic --wallet 54mbv-kyaaa-aaaar-qbn5a-cai
dfx canister install usdc_ledger --argument '(variant { Upgrade = opt record { metadata = opt vec { record { "icrc1:logo"; variant { Text = "data:image/svg+xml;base64," }} }; }})' --wallet 54mbv-kyaaa-aaaar-qbn5a-cai --ic --mode upgrade --upgrade-unchanged
dfx canister start usdc_ledger --ic --wallet 54mbv-kyaaa-aaaar-qbn5a-cai